// Combine lead qualification data with contact info
const lead = $('Fetch Lead Data').first().json.fields;
const contacts = ($('Fetch Contacts').first().json.records || []).map(r => r.fields);
const channel = $('Webhook: Generate Outreach').first().json.channel || 'all';

let qualification = {};
try {
  qualification = JSON.parse(lead.qualification_json || '{}');
} catch (e) {
  qualification = { error: 'Could not parse qualification data' };
}

// Pick the best contact (highest confidence or first buyer/owner title)
const bestContact = contacts.sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0] || {
  first_name: '[First Name]',
  last_name: '[Last Name]',
  title: '[Title]',
  email: '[email]'
};

return [{
  json: {
    lead_id: $('Webhook: Generate Outreach').first().json.lead_id,
    channel: channel,
    contact: bestContact,
    qualification: {
      retailer_name: lead.retailer_name,
      lead_score: lead.lead_score,
      recommendation: lead.recommendation,
      pitch_angle: qualification.lead_score?.pitch_angle || '',
      shared_brands: (qualification.brand_overlap?.shared_brands || []).map(b => b.brand),
      brands_to_pitch: (qualification.brand_overlap?.you_carry_they_dont || []).map(b => b.brand),
      store_type: qualification.overview?.store_type || '',
      brand_positioning: qualification.overview?.brand_positioning || ''
    }
  }
}];

